// In inference/src/lib.rs

/// Cumulative distribution function for Student's t-distribution using statrs
fn t_cdf(t: f64, df: i32) -> Result<f64, InferenceError> {
    if df <= 0 {
        return Err(InferenceError::DegreesOfFreedom(df));
    }

    if t.is_infinite() {
        return Ok(if t > 0.0 { 1.0 } else { 0.0 });
    }

    StudentsT::new(0.0, 1.0, df as f64)
        .map(|dist| dist.cdf(t))
        .map_err(|e| InferenceError::Matrix(e.to_string())) // Or a more specific error
}

// The calling function `t_test_p_values` would then need to handle the Result.
pub fn t_test_p_values(t_stats: &[f64], df: i32) -> Result<Vec<f64>, InferenceError> {
    t_stats
        .iter()
        .map(|&t| {
            let abs_t = t.abs();
            // Two-tailed p-value: P(|T| > |t|) = 2 * P(T > |t|)
            t_cdf(abs_t, df).map(|cdf_val| 2.0 * (1.0 - cdf_val))
        })
        .collect()
}
```
